// A new note landed in the vault. The folder it landed in decides which agent
// owns it, i.e. which agent should be triggered to act on the handoff.
// Config-driven: reads the same GHIATH_ROUTES env var as the router (agent ->
// {port, model, folder}); falls back to neutral defaults.
const fs = require('fs');
const DEFAULT_ROUTES = {
  assistant:  { port: 8642, model: 'deepseek/deepseek-v2-flash', folder: 'scratchpads' },
  engineer:   { port: 8643, model: 'anthropic/claude-opus-4-8', folder: 'projects' },
  researcher: { port: 8644, model: 'z-ai/glm-4.6', folder: 'memory' },
};
let routes = DEFAULT_ROUTES;
try { if ($env.GHIATH_ROUTES) routes = JSON.parse($env.GHIATH_ROUTES); } catch (e) {}

// Build folder -> agent map from the config.
const agentByFolder = {};
for (const [name, cfg] of Object.entries(routes)) { if (cfg.folder) agentByFolder[cfg.folder] = name; }
const folders = Object.keys(agentByFolder);
if (!folders.length) return [];

const path = ($input.first().json.path || '').toString();
if (!path.endsWith('.md')) return [];

// The vault is always mounted inside n8n at /data/vault regardless of
// its host folder name, so match against that fixed internal path.
const folderRe = new RegExp('/data/vault/(' + folders.join('|') + ')/');
const m = path.match(folderRe);
if (!m) return [];

// Loop guard: only "open" notes are handoffs to act on. An agent's own output
// is written with status "done" (or type "result"), so it never re-triggers.
// Notes without front-matter are treated as human-created open tasks.
let status = 'open';
try {
  const raw = fs.readFileSync(path, 'utf8');
  const fm = raw.match(/^---\n([\s\S]*?)\n---/);
  if (fm) {
    const s = fm[1].match(/^status:\s*(\S+)/m);
    if (s) status = s[1].toLowerCase();
  }
} catch (e) {
  // Unreadable (e.g. mid-write); skip this pass rather than misfire.
  return [];
}
if (status !== 'open') return [];

const folder = m[1];
const agent = agentByFolder[folder];
const r = routes[agent];
const url = `http://host.docker.internal:${r.port}/v1/chat/completions`;

// Path as the agent sees it on the host (agents run on the host, not in n8n).
const hostPath = path.replace('/data/vault/', '');
const prompt = `An open note was placed in your folder: ${hostPath}\nRead it, set its status to "doing", act on it, then set its status to "done". Record your result as a note with type "result", status "done", owner yourself. If the task should move to another agent, drop an "open" note in that agent's folder with owner set to them.`;

return [{ json: { agent, folder, url, model: r.model, prompt, note: hostPath } }];
